from machine import PWM, Pin, TouchPad
import time

# Inicializamos el Pin 13 como salida para el PWM
buzzer = PWM(Pin(15)) 
#buzzer.duty(0) # Inicialmente apagado (silencio)

# Botones Touch distribuidos físicamente:
# Botón 1: Pin 4 (Esquina inferior derecha)
# Botón 2: Pin 32 (Esquina superior izquierda - lejos de los otros)
# Botón 3: Pin 33 (Esquina superior izquierda - adyacente a T9)
# Botón 4: Pin 27 (Lado inferior izquierdo)
boton = TouchPad(Pin(4))
boton1 = TouchPad(Pin(13))
boton2 = TouchPad(Pin(33))
boton3 = TouchPad(Pin(27))



buzzer.duty(0)


led = Pin(2, Pin.OUT) # LED para indicar que la canción está sonando
led.off()

def tocar_cancion(melodia):
    for nota, duracion in melodia:
        if nota == 0:
            buzzer.duty(0) # Apaga la señal (silencio)
        else:
            buzzer.freq(nota)
            buzzer.duty(512) # 50% de ciclo de trabajo (volumen medio)
        
        time.sleep_ms(duracion)
    
    buzzer.duty(0) # Apagar al terminar

# Asegúrate de tener tu lista 'melodia' definida antes de llamar a esto
# tocar_cancion(melodia)
