def check_boton(boton, melodia):
    valor = boton.read()
    print(valor) # Lee el valor del botón táctil
    if valor < 500: # Si el botón táctil es presionado
        led.value(1) # Enciende el LED para indicar que la canción está sonando
        tocar_cancion(melodia) # Reproduce la canción
        led.value(0) # Apaga el LED al terminar la canción


